pub const GS_CONNECT: u16 = 1024;
pub const GSH_GAME_STATUS_CHANGE: u16 = 1145;
pub const GS_MESSAGE: u16 = 1153;
pub const GS_PLAYER_ORDER: u16 = 1155;
pub const GS_REPLAY_MESSAGE: u16 = 1156;

